# Organization Policy to prevent public bucket access
resource "google_organization_policy" "restrict_public_buckets" {
  org_id     = var.organization_id
  constraint = "storage.publicAccessPrevention"

  list_policy {
    deny {
      values = ["allUsers", "allAuthenticatedUsers"]
    }
  }
}

# Organization Policy to enforce uniform bucket-level access
resource "google_organization_policy" "enforce_uniform_bucket_access" {
  org_id     = var.organization_id
  constraint = "storage.uniformBucketLevelAccess"

  boolean_policy {
    enforced = true
  }
}

# Secure GCS bucket with uniform bucket-level access
resource "google_storage_bucket" "secure_data_bucket" {
  name          = "${var.project_id}-secure-data"
  location      = "US"
  project       = var.project_id
  force_destroy = false

  # Enable uniform bucket-level access (IAM only, no ACLs)
  uniform_bucket_level_access {
    enabled = true
  }

  # Enable public access prevention (blocks allUsers/allAuthenticatedUsers)
  public_access_prevention = "enforced"

  # Enable versioning for data recovery
  versioning {
    enabled = true
  }

  # Encryption with customer-managed keys
  encryption {
    default_kms_key_name = google_kms_crypto_key.bucket_key.id
  }

  # Lifecycle rules for cost optimization
  lifecycle_rule {
    condition {
      age = 90
    }
    action {
      type          = "SetStorageClass"
      storage_class = "NEARLINE"
    }
  }

  # Audit logging
  logging {
    log_bucket = google_storage_bucket.audit_logs.name
  }
}

# IAM binding with least privilege (service account only)
resource "google_storage_bucket_iam_member" "app_service_account" {
  bucket = google_storage_bucket.secure_data_bucket.name
  role   = "roles/storage.objectViewer"
  member = "serviceAccount:${google_service_account.app_sa.email}"

  condition {
    title       = "Restrict to VPC"
    description = "Access only from authorized VPC network"
    expression  = "resource.name.startsWith('projects/${var.project_id}/buckets/${google_storage_bucket.secure_data_bucket.name}') && origin.ip.startsWith('10.0.0.0/8')"
  }
}

# VPC Service Controls perimeter
resource "google_access_context_manager_service_perimeter" "storage_perimeter" {
  parent = "accessPolicies/${var.access_policy_id}"
  name   = "accessPolicies/${var.access_policy_id}/servicePerimeters/storage_perimeter"
  title  = "Storage Security Perimeter"

  status {
    restricted_services = [
      "storage.googleapis.com",
      "storage-component.googleapis.com"
    ]

    resources = [
      "projects/${var.project_number}"
    ]

    vpc_accessible_services {
      enable_restriction = true
      allowed_services = [
        "storage.googleapis.com"
      ]
    }
  }
}

const { Storage } = require('@google-cloud/storage');
const crypto = require('crypto');

// Initialize Storage client with service account credentials
const storage = new Storage({
  projectId: process.env.GCP_PROJECT_ID,
  keyFilename: process.env.GOOGLE_APPLICATION_CREDENTIALS // Path to service account JSON
});

const bucketName = 'company-private-data';
const bucket = storage.bucket(bucketName);

/**
 * Generate signed URL for temporary read access
 * @param {string} fileName - Object name in bucket
 * @param {number} expirationMinutes - URL expiration in minutes (max 7 days)
 * @returns {Promise<string>} Signed URL
 */
async function generateSignedReadUrl(fileName, expirationMinutes = 15) {
  const file = bucket.file(fileName);

  const options = {
    version: 'v4',
    action: 'read',
    expires: Date.now() + expirationMinutes * 60 * 1000, // 15 minutes by default

    // Optional: Add custom response headers
    responseDisposition: 'attachment; filename="download.pdf"',
    responseType: 'application/pdf',

    // Optional: Query parameters for additional security
    queryParams: {
      'x-goog-user-id': crypto.randomBytes(16).toString('hex') // User tracking
    }
  };

  try {
    const [url] = await file.getSignedUrl(options);

    // Log URL generation for audit trail
    console.log('Generated signed URL', {
      file: fileName,
      expiresAt: new Date(options.expires).toISOString(),
      timestamp: new Date().toISOString()
    });

    return url;
  } catch (error) {
    console.error('Error generating signed URL:', error);
    throw new Error('Failed to generate secure download link');
  }
}

/**
 * Generate signed URL for temporary upload access
 * @param {string} fileName - Object name for upload
 * @param {string} contentType - MIME type of file
 * @param {number} expirationMinutes - URL expiration in minutes
 * @returns {Promise<string>} Signed upload URL
 */
async function generateSignedUploadUrl(fileName, contentType, expirationMinutes = 15) {
  const file = bucket.file(fileName);

  const options = {
    version: 'v4',
    action: 'write',
    expires: Date.now() + expirationMinutes * 60 * 1000,
    contentType: contentType,

    // Enforce content type validation
    extensionHeaders: {
      'x-goog-content-length-range': '0,10485760' // Max 10MB
    }
  };

  try {
    const [url] = await file.getSignedUrl(options);
    return url;
  } catch (error) {
    console.error('Error generating upload URL:', error);
    throw new Error('Failed to generate secure upload link');
  }
}

/**
