const express = require('express');
const app = express();

app.get('/api/files/:fileId/download', async (req, res) => {
  try {
    const { fileId } = req.params;
    const userId = req.user.id; // From authentication middleware

    // 1. Verify user has permission to access this file
    const hasAccess = await checkUserFilePermission(userId, fileId);
    if (!hasAccess) {
      return res.status(403).json({ error: 'Access denied' });
    }

    // 2. Get file path from database
    const filePath = await getFilePathFromDatabase(fileId);

    // 3. Generate short-lived signed URL (15 minutes)
    const signedUrl = await generateSignedReadUrl(filePath, 15);

    // 4. Log access for compliance audit
    await logFileAccess({
      userId,
      fileId,
      filePath,
      action: 'download',
      timestamp: new Date(),
      ipAddress: req.ip
    });

    // 5. Return signed URL to client
    res.json({
      downloadUrl: signedUrl,
      expiresIn: 900 // 15 minutes in seconds
    });

  } catch (error) {
    console.error('Download error:', error);
    res.status(500).json({ error: 'Failed to generate download link' });
  }
});

/**
 * Policy-based signed URL generation with advanced validation
 */
async function generateSignedUrlWithPolicy(fileName) {
  const file = bucket.file(fileName);

  // V4 signing policy for fine-grained control
  const policy = {
    version: 'v4',
    action: 'read',
    expires: Date.now() + 15 * 60 * 1000,

    // Conditional access based on IP range
    conditions: [
      ['eq', '$bucket', bucketName],
      ['eq', '$key', fileName],
      ['content-length-range', 0, 10485760]
    ],

    // Additional security headers
    extensionHeaders: {
      'x-goog-encryption-algorithm': 'AES256',
      'x-goog-meta-user-id': 'validated-user-id'
    }
  };

  const [url] = await file.getSignedUrl(policy);
  return url;
}

